class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.length();
        vector<int> dp(k + 1, INT_MAX);
        dp[0] = 0;
        for (int i = 1; i <= k; ++i) {
            for (int j = i; j <= n; j += i) {
                int changes = 0;
                for (int l = 0; l < i / 2; ++l) {
                    if (s[j - l - 1] != s[j - l]) {
                        changes++;
                    }
                }
                dp[i] = min(dp[i], dp[i - 1] + changes);
            }
        }
        return dp[k];
    }
};
